#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *a = (int*)malloc((N+1)*sizeof(int));
        int *pos = (int*)malloc((N+1)*sizeof(int));
        for(int i=1;i<=N;i++){
            scanf("%d", &a[i]);
            pos[a[i]] = i;
        }
        // store operations in dynamic arrays (max N)
        int *L = (int*)malloc((N+1)*sizeof(int));
        int *R = (int*)malloc((N+1)*sizeof(int));
        int ops = 0;
        for(int x=N;x>=1;x--){
            int idx = pos[x];
            if(idx==x) continue;
            int l = idx < x ? idx : x;
            int r = idx > x ? idx : x;
            L[ops] = l; R[ops] = r; ops++;
            // swap a[l] and a[r]
            int v1 = a[l];
            int v2 = a[r];
            a[l] = v2; a[r] = v1;
            pos[v1] = r; pos[v2] = l;
        }
        printf("%d\n", ops);
        for(int i=0;i<ops;i++) printf("%d %d\n", L[i], R[i]);
        free(a); free(pos); free(L); free(R);
    }
    return 0;
}

