int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> a(N+1), pos(N+1);
        for(int i=1;i<=N;i++){
            cin>>a[i];
            pos[a[i]]=i;
        }
        vector<pair<int,int>> ops;
        for(int x=N;x>=1;x--){
            int idx = pos[x];
            if(idx==x) continue;
            int l = min(x, idx), r = max(x, idx);
            ops.emplace_back(l,r);
            int v1=a[l], v2=a[r];
            swap(a[l], a[r]);
            pos[v1]=r; pos[v2]=l;
        }
        cout<<ops.size()<<'\n';
        for(auto &p:ops) cout<<p.first<<' '<<p.second<<'\n';
    }
    return 0;
}

