import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] a = new int[N + 1];
            int[] pos = new int[N + 1];
            for (int i = 1; i <= N; i++) {
                a[i] = fs.nextInt();
                pos[a[i]] = i;
            }
            List<int[]> ops = new ArrayList<>();
            for (int x = N; x >= 1; x--) {
                int idx = pos[x];
                if (idx == x) continue;
                int l = Math.min(x, idx);
                int r = Math.max(x, idx);
                ops.add(new int[]{l, r});
                int v1 = a[l];
                int v2 = a[r];
                a[l] = v2; a[r] = v1;
                pos[v1] = r; pos[v2] = l;
            }
            out.append(ops.size()).append('\n');
            for (int[] p : ops) out.append(p[0]).append(' ').append(p[1]).append('\n');
        }
        System.out.print(out.toString());
    }

    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

