const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let output = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const a = new Array(N + 1);
  const pos = new Array(N + 1);
  for (let i = 1; i <= N; i++) {
    const v = input[idx++];
    a[i] = v;
    pos[v] = i;
  }
  const ops = [];
  for (let x = N; x >= 1; x--) {
    const cur = pos[x];
    if (cur === x) continue;
    const l = Math.min(x, cur);
    const r = Math.max(x, cur);
    ops.push([l, r]);
    const v1 = a[l];
    const v2 = a[r];
    a[l] = v2; a[r] = v1;
    pos[v1] = r; pos[v2] = l;
  }
  output.push(String(ops.length));
  for (const [l, r] of ops) output.push(l + ' ' + r);
}
